这篇文章不依赖任何框架（LangChain &#x2F; CrewAI &#x2F; AutoGen），只用纯 Python 讲透 Agent 开发的通用模式。读完你会理解：Agent 的肚子里到底发生了什么，以及如何从零构建一个能在生产环境中可靠运行的 Agent。 一、核心骨架：50 行 Python 构建一个 Agent先看完整骨架，再逐一拆解。这个 Agent 可以接收用户指令、调用工具、根据结果继续思考，直到任务完成。 123456789101112131415161718192021222324252627282930313233import jsonfrom openai import OpenAIclass Agent: def __init__(self, tools: dict, system_prompt: str): self.tools = tools # 工具注册表 self.system_prompt = system_prompt self.messages = [&#123;&quot;role&quot;: &quot;system&quot;, &quot;content&quot;: system_prompt&#125;] self.client = OpenAI() def run(self, user_input: str) -&gt; str: self.messages.append(&#123;&quot;role&quot;: &quot;user&quot;, &quot;content&quot;: user_input&#125;) while True: response = self.client.chat.completions.create( model=&quot;gpt-4o&quot;, messages=self.messages, tools=self._get_tool_schemas() ) msg = response.choices[0].message if msg.tool_calls: # → 需要调工具 for tc in msg.tool_calls: name = tc.function.name args = json.loads(tc.function.arguments) result = self.tools[name](**args) # 执行工具 self.messages.append(&#123; &quot;role&quot;: &quot;tool&quot;, &quot;tool_call_id&quot;: tc.id, &quot;content&quot;: json.dumps(result, ensure_ascii=False) &#125;) else: # → 最终回答 return msg.content 拆解四个核心组件： 组件 职责 代码体现 LLM 调用 接收上下文，返回 Thought 或 Tool Call client.chat.completions.create() 工具注册表 函数名 → 实际函数映射 self.tools 消息历史 存储 system + user + tool 全部消息 self.messages ReAct 循环 思考 → 行动 → 观察 → 重复 run() 中的 while True 运行示例： 12345678910111213def get_weather(city: str) -&gt; dict: return &#123;&quot;city&quot;: city, &quot;temp&quot;: 25, &quot;condition&quot;: &quot;晴朗&quot;&#125;def add_calendar(event: str, time: str) -&gt; dict: return &#123;&quot;status&quot;: &quot;success&quot;, &quot;event&quot;: event, &quot;time&quot;: time&#125;agent = Agent( tools=&#123;&quot;get_weather&quot;: get_weather, &quot;add_calendar&quot;: add_calendar&#125;, system_prompt=&quot;你是生活助手。当用户需要查天气时调用 get_weather，需要加日程时调用 add_calendar。&quot;)result = agent.run(&quot;明天下午去北京野餐，帮我查天气，好的话加日程&quot;)# → &quot;北京明天晴朗，25度，非常适合野餐！已帮您添加&#x27;北京野餐&#x27;到明天下午的日程。&quot; Agent 循环日志： 12345第1轮：LLM → need get_weather(city=&quot;北京&quot;) Agent 执行 → &#123;&quot;temp&quot;: 25, &quot;condition&quot;: &quot;晴朗&quot;&#125;第2轮：LLM → 天气晴朗 → need add_calendar(event=&quot;北京野餐&quot;, time=&quot;明天下午&quot;) Agent 执行 → &#123;&quot;status&quot;: &quot;success&quot;&#125;第3轮：LLM → 全部完成 → 返回最终回答 二、LLM 集成：封装模型调用Agent 不应该绑定特定模型。用抽象基类统一接口： 12345678910111213141516171819202122232425262728293031323334353637383940from abc import ABC, abstractmethodfrom dataclasses import dataclass@dataclassclass LLMResponse: content: str | None = None tool_calls: list[dict] | None = Noneclass LLMProvider(ABC): @abstractmethod def chat(self, messages: list[dict], tools: list[dict] = None) -&gt; LLMResponse: passclass OpenAIProvider(LLMProvider): def __init__(self, model: str = &quot;gpt-4o&quot;, api_key: str = None): self.model = model self.client = OpenAI(api_key=api_key) def chat(self, messages, tools=None) -&gt; LLMResponse: resp = self.client.chat.completions.create( model=self.model, messages=messages, tools=tools ) msg = resp.choices[0].message if msg.tool_calls: return LLMResponse(tool_calls=[ &#123;&quot;id&quot;: tc.id, &quot;name&quot;: tc.function.name, &quot;args&quot;: json.loads(tc.function.arguments)&#125; for tc in msg.tool_calls ]) return LLMResponse(content=msg.content)class AnthropicProvider(LLMProvider): def chat(self, messages, tools=None) -&gt; LLMResponse: # 同样的接口，不同的实现 ...class OllamaProvider(LLMProvider): def chat(self, messages, tools=None) -&gt; LLMResponse: # 本地模型，零成本调用 ... System Prompt 设计要点： 要素 说明 示例 角色定义 告诉模型”你是谁” “你是一个拥有10年经验的Python后端工程师” 工具使用规则 何时调用工具、如何选工具 “当需要实时数据时，调用对应工具而非猜测” 输出约束 格式要求 “最终回答使用中文，工具调用参数使用英文” 边界说明 明确不能做什么 “不要执行 rm、sudo 等危险命令” 错误处理关键代码： 12345678910def chat_with_retry(self, messages, tools=None, max_retries=3): for attempt in range(max_retries): try: return self.chat(messages, tools) except RateLimitError: time.sleep(2 ** attempt) # 指数退避 except json.JSONDecodeError: # LLM 返回了非法 JSON → 让 LLM 自我修正 messages.append(&#123;&quot;role&quot;: &quot;user&quot;, &quot;content&quot;: &quot;你的输出格式错误，请重新输出符合 JSON Schema 的格式。&quot;&#125;) raise Exception(&quot;LLM 调用失败，已达最大重试次数&quot;) 三、工具定义与调用工具 Schema 设计（JSON Schema 标准）： 1234567891011121314151617TOOL_GET_WEATHER = &#123; &quot;type&quot;: &quot;function&quot;, &quot;function&quot;: &#123; &quot;name&quot;: &quot;get_weather&quot;, &quot;description&quot;: &quot;获取指定城市当前天气信息，包括温度、湿度、天气状况&quot;, &quot;parameters&quot;: &#123; &quot;type&quot;: &quot;object&quot;, &quot;properties&quot;: &#123; &quot;city&quot;: &#123; &quot;type&quot;: &quot;string&quot;, &quot;description&quot;: &quot;城市名称，如&#x27;北京&#x27;、&#x27;Shanghai&#x27;&quot; &#125; &#125;, &quot;required&quot;: [&quot;city&quot;] &#125; &#125;&#125; 工具注册与执行： 1234567891011121314151617181920212223242526272829class ToolRegistry: def __init__(self): self._tools: dict[str, dict] = &#123;&#125; def register(self, func: callable, schema: dict): &quot;&quot;&quot;注册工具：函数 + JSON Schema&quot;&quot;&quot; name = schema[&quot;function&quot;][&quot;name&quot;] self._tools[name] = &#123;&quot;func&quot;: func, &quot;schema&quot;: schema&#125; def execute(self, name: str, args: dict) -&gt; str: &quot;&quot;&quot;执行工具，统一返回 JSON 字符串&quot;&quot;&quot; if name not in self._tools: return json.dumps(&#123;&quot;error&quot;: f&quot;工具 &#x27;&#123;name&#125;&#x27; 不存在&quot;&#125;) try: result = self._tools[name][&quot;func&quot;](**args) return json.dumps(result, ensure_ascii=False) except Exception as e: return json.dumps(&#123;&quot;error&quot;: str(e)&#125;) def get_schemas(self) -&gt; list[dict]: return [t[&quot;schema&quot;] for t in self._tools.values()]# 使用装饰器注册更优雅registry = ToolRegistry()@registry.register(TOOL_GET_WEATHER)def get_weather(city: str) -&gt; dict: # 实际调用天气 API return &#123;&quot;city&quot;: city, &quot;temp&quot;: 25, &quot;humidity&quot;: &quot;60%&quot;&#125; 工具调用最佳实践： 实践 原因 实现 重试 + 自我修正 工具执行失败时，把错误信息返回给 LLM 让它重新决策 execute() 返回 error JSON 超时控制 防止单个工具调用卡死整个 Agent signal.alarm() 或 asyncio.wait_for() 并发 vs 串行 读文件可并发，写文件必须串行 标记工具属性 &quot;safe_for_parallel&quot;: True 描述决定准确率 LLM 根据描述选择工具——描述越清晰，选工具越准 description 字段写详细 四、MCP Server 开发MCP (Model Context Protocol) 是 AI 工具接口的行业标准。你写的 MCP Server 可以被任何支持 MCP 的 AI 应用使用。 用 Python 从零构建： 1234567891011121314151617181920212223242526272829303132333435363738394041# weather_server.pyimport jsonimport sysfrom mcp.server import Serverfrom mcp.server.stdio import stdio_serverfrom mcp.types import Tool, TextContentserver = Server(&quot;weather-server&quot;)@server.list_tools()async def list_tools() -&gt; list[Tool]: return [ Tool( name=&quot;get_weather&quot;, description=&quot;获取指定城市当前天气信息&quot;, inputSchema=&#123; &quot;type&quot;: &quot;object&quot;, &quot;properties&quot;: &#123; &quot;city&quot;: &#123;&quot;type&quot;: &quot;string&quot;, &quot;description&quot;: &quot;城市名称&quot;&#125; &#125;, &quot;required&quot;: [&quot;city&quot;] &#125; ) ]@server.call_tool()async def call_tool(name: str, arguments: dict) -&gt; list[TextContent]: if name == &quot;get_weather&quot;: city = arguments[&quot;city&quot;] # 实际调用天气 API result = &#123;&quot;city&quot;: city, &quot;temp&quot;: 25, &quot;condition&quot;: &quot;晴朗&quot;&#125; return [TextContent(type=&quot;text&quot;, text=json.dumps(result, ensure_ascii=False))] raise ValueError(f&quot;未知工具: &#123;name&#125;&quot;)async def main(): async with stdio_server() as (read_stream, write_stream): await server.run(read_stream, write_stream, server.create_initialization_options())if __name__ == &quot;__main__&quot;: import asyncio asyncio.run(main()) 配置使用（在 Claude Desktop &#x2F; Cursor 中）： 123456789&#123; &quot;mcpServers&quot;: &#123; &quot;weather&quot;: &#123; &quot;command&quot;: &quot;python&quot;, &quot;args&quot;: [&quot;weather_server.py&quot;], &quot;env&quot;: &#123;&quot;OPENWEATHER_API_KEY&quot;: &quot;your_key&quot;&#125; &#125; &#125;&#125; MCP 三种能力对比： 能力 用途 谁控制 示例 Tools 可执行操作 LLM 决定何时调用 查天气、发邮件、查数据库 Resources 只读数据暴露 Agent 按需读取 文档内容、数据库 Schema Prompts 预置提示模板 用户手动触发 “帮我审查这段代码的安全性” 五、记忆与上下文管理三层记忆架构： 层级 存储位置 生命周期 容量 短期记忆 self.messages 列表 单次会话 受 Context Window 限制 中期记忆 向量数据库 + RAG 跨会话（数天到数周） 几十万条 长期记忆 配置文件 &#x2F; 数据库 永久 项目规则、用户偏好 短期记忆实现： 12345678910111213141516171819202122class Memory: def __init__(self, max_tokens: int = 8000): self.messages: list[dict] = [] self.max_tokens = max_tokens def add(self, message: dict): self.messages.append(message) self._compact_if_needed() def _compact_if_needed(self): &quot;&quot;&quot;当 Token 用量接近上限时，自动压缩&quot;&quot;&quot; while self._estimate_tokens() &gt; self.max_tokens: removed = self.messages.pop(1) # 保留 system prompt # 可选：将 removed 的内容用 LLM 总结后保留 def _estimate_tokens(self) -&gt; int: &quot;&quot;&quot;粗略估算：中文约 1 字 ≈ 1 Token，英文约 4 字符 ≈ 1 Token&quot;&quot;&quot; total = sum(len(str(m.get(&quot;content&quot;, &quot;&quot;))) for m in self.messages) return int(total * 0.6) # 经验系数 def get_context(self, last_n: int = None) -&gt; list[dict]: return self.messages if last_n is None else self.messages[-last_n:] 长期记忆集成（向量数据库）： 1234567891011121314151617181920212223242526272829class LongTermMemory: def __init__(self, vector_db, embedder): self.db = vector_db # 如 ChromaDB / Milvus / PGVector self.embedder = embedder # 如 text-embedding-3-small def store(self, content: str, metadata: dict): embedding = self.embedder.embed(content) self.db.insert(embedding=embedding, metadata=metadata, text=content) def retrieve(self, query: str, top_k: int = 5) -&gt; list[str]: embedding = self.embedder.embed(query) results = self.db.search(embedding, top_k) return [r[&quot;text&quot;] for r in results]# 在 Agent 中使用class AgentWithMemory(Agent): def __init__(self, *args, long_term_memory: LongTermMemory = None, **kwargs): super().__init__(*args, **kwargs) self.ltm = long_term_memory def run(self, user_input: str) -&gt; str: if self.ltm: # 注入相关知识到上下文 relevant = self.ltm.retrieve(user_input, top_k=3) self.memory.add(&#123; &quot;role&quot;: &quot;system&quot;, &quot;content&quot;: &quot;相关历史信息：
&quot; + &quot;
&quot;.join(relevant) &#125;) return super().run(user_input) 六、Skill 开发Skill 是”可复用的流程级指令包”。Prompt 是”一次性指令”，Skill 是”菜谱”——每次自动按流程来。 SKILL.md 编写规范： 1234567891011121314151617181920212223242526272829# Skill: PR 代码审查## 触发条件当用户请求审查代码变更、PR 或 git diff 时自动激活。## 前置准备1. 使用 `git diff` 获取所有变更文件列表2. 排除自动生成的文件（*.min.js, *.lock, package-lock.json）## 审查流程对每个变更文件，按以下顺序检查：### 1. 安全检查（最高优先级）- SQL 注入：是否有字符串拼接的 SQL 语句？- XSS：是否有未转义的用户输入直接输出到 HTML？- 敏感信息：是否硬编码了密钥、Token、密码？### 2. 逻辑正确性- 边界条件：空数组、null、0 值是否处理？- 错误处理：异常是否正确捕获和传播？### 3. 性能- 循环内是否有不必要的数据库查询？- 大数据量操作是否有分页？## 输出格式- 🔴 严重：必须修复（有安全风险或逻辑错误）- 🟡 建议：建议优化（性能或可读性问题）- 🔵 风格：可选（代码风格建议） SkillLoader 加载机制： 1234567891011121314151617181920212223242526272829303132from pathlib import Pathclass SkillLoader: def __init__(self, skills_dir: str): self.skills = &#123;&#125; for skill_file in Path(skills_dir).rglob(&quot;SKILL.md&quot;): name = skill_file.parent.name content = skill_file.read_text(encoding=&quot;utf-8&quot;) self.skills[name] = self._parse(content) def _parse(self, content: str) -&gt; dict: &quot;&quot;&quot;解析 SKILL.md 为结构化对象&quot;&quot;&quot; return &#123; &quot;raw&quot;: content, &quot;trigger&quot;: self._extract_section(content, &quot;触发条件&quot;), &quot;workflow&quot;: self._extract_section(content, &quot;审查流程&quot;), &quot;output_format&quot;: self._extract_section(content, &quot;输出格式&quot;), &#125; def match(self, user_input: str) -&gt; list[str]: &quot;&quot;&quot;根据用户输入匹配相关技能&quot;&quot;&quot; matched = [] for name, skill in self.skills.items(): for keyword in skill.get(&quot;trigger&quot;, &quot;&quot;).split(): if keyword.lower() in user_input.lower(): matched.append(name) return matched def inject(self, system_prompt: str, skill_name: str) -&gt; str: &quot;&quot;&quot;将技能注入到 system prompt 中&quot;&quot;&quot; skill = self.skills[skill_name] return f&quot;&#123;system_prompt&#125;

## 当前激活技能：&#123;skill_name&#125;
&#123;skill[&#x27;raw&#x27;]&#125;&quot; 七、多 Agent 协作当一个 Agent 搞不定复杂任务时，需要多个 Agent 分工协作。 四种编排模式： 模式 结构 适用场景 关键特征 DAG 固定流程 A→B→C 文档处理流水线 任务依赖图，可并行 Supervisor 一个主管分配任务 代码审查 + 修复 集中决策，分工明确 Swarm 多个平等 Agent 自主认领 并行搜索 + 汇总 去中心化，弹性伸缩 Handoff Agent A 完成后交接给 Agent B 客服 → 技术专家 按阶段接力 Supervisor 模式实现： 123456789101112131415161718192021222324252627282930313233class SupervisorAgent: def __init__(self, workers: dict[str, Agent], llm: LLMProvider): self.workers = workers self.llm = llm def run(self, task: str) -&gt; str: # Step 1: LLM 拆解任务 plan = self._decompose(task) # 如: [&#123;&quot;worker&quot;: &quot;searcher&quot;, &quot;task&quot;: &quot;搜索相关资料&quot;&#125;, # &#123;&quot;worker&quot;: &quot;coder&quot;, &quot;task&quot;: &quot;根据资料写代码&quot;&#125;, # &#123;&quot;worker&quot;: &quot;reviewer&quot;, &quot;task&quot;: &quot;审查代码质量和安全&quot;&#125;] results = &#123;&#125; for step in plan: worker_name = step[&quot;worker&quot;] subtask = step[&quot;task&quot;] results[worker_name] = self.workers[worker_name].run(subtask) # Step 2: LLM 汇总结果 summary = self._synthesize(task, results) return summary def _decompose(self, task: str) -&gt; list[dict]: prompt = f&quot;&quot;&quot;你是任务规划专家。将以下任务拆解为子任务，分配给可用的 Worker。可用 Worker: &#123;list(self.workers.keys())&#125;任务: &#123;task&#125;输出 JSON: [&#123;&#123;&quot;worker&quot;: &quot;...&quot;, &quot;task&quot;: &quot;...&quot;&#125;&#125;]&quot;&quot;&quot; resp = self.llm.chat([&#123;&quot;role&quot;: &quot;user&quot;, &quot;content&quot;: prompt&#125;]) return json.loads(resp.content) def _synthesize(self, task: str, results: dict) -&gt; str: prompt = f&quot;&quot;&quot;原始任务: &#123;task&#125;
各 Worker 结果: &#123;results&#125;
请汇总成最终回答。&quot;&quot;&quot; return self.llm.chat([&#123;&quot;role&quot;: &quot;user&quot;, &quot;content&quot;: prompt&#125;]).content Handoff 模式实现： 12345678910111213141516171819class HandoffAgent: def __init__(self, agents: dict[str, Agent]): self.agents = agents self.current = &quot;general&quot; # 当前活跃 Agent def run(self, user_input: str) -&gt; str: # 判断是否需要切换 Agent switch = self._should_switch(user_input) if switch and switch != self.current: self.current = switch return f&quot;正在转接给 &#123;switch&#125; 专家...&quot; result = self.agents[self.current].run(user_input) # 检查是否需要交接 if &quot;需要转接给&quot; in result: self.current = self._extract_target(result) return self.agents[self.current].run(user_input) return result 八、测试与调试Agent 的测试难点：非确定性输出——同一个输入，每次结果可能不同。 测试金字塔： 层级 方法 测试什么 示例 单元测试 直接调用函数 单个 Tool 逻辑正确 assert get_weather(&quot;北京&quot;)[&quot;city&quot;] == &quot;北京&quot; 集成测试 Mock LLM 返回 Agent 循环逻辑 固定 LLM 返回 tool_call, 验证 Agent 是否正确执行 E2E 测试 真实 LLM + 测试集 整体质量 10 个标准任务, 人工评估完成率 评估基准 LLM-as-Judge 对比不同版本 用 GPT-4 给 Agent 的回答打分 (1-5) 集成测试示例： 12345678910def test_agent_loop_with_mock_llm(): # 构造一个&quot;假 LLM&quot;：第一次返回 tool_call，第二次返回 final answer mock_llm = MockLLM(responses=[ LLMResponse(tool_calls=[&#123;&quot;id&quot;: &quot;1&quot;, &quot;name&quot;: &quot;get_weather&quot;, &quot;args&quot;: &#123;&quot;city&quot;: &quot;北京&quot;&#125;&#125;]), LLMResponse(content=&quot;北京天气晴朗，25度&quot;) ]) agent = Agent(tools=&#123;&quot;get_weather&quot;: lambda city: &#123;&quot;temp&quot;: 25&#125;&#125;, llm=mock_llm) result = agent.run(&quot;北京天气怎么样？&quot;) assert &quot;晴朗&quot; in result assert &quot;25度&quot; in result DebugAgent 调试技巧： 1234567891011121314151617181920212223242526272829303132333435363738class DebugAgent(Agent): def __init__(self, *args, **kwargs): super().__init__(*args, **kwargs) self.trace = [] # 完整追踪 def run(self, user_input: str) -&gt; str: self.trace = [] self.messages.append(&#123;&quot;role&quot;: &quot;user&quot;, &quot;content&quot;: user_input&#125;) round_num = 0 while True: round_num += 1 response = self._call_llm() self.trace.append(&#123; &quot;round&quot;: round_num, &quot;messages_count&quot;: len(self.messages), &quot;estimated_tokens&quot;: self._estimate_tokens() &#125;) if response.tool_calls: for tc in response.tool_calls: self.trace[-1][&quot;tool_calls&quot;] = tc result = self._execute_tool(tc) self.trace[-1][&quot;tool_result&quot;] = result[:200] # 截断 else: self.trace[-1][&quot;final_answer&quot;] = response.content self._print_trace() return response.content def _print_trace(self): for t in self.trace: print(f&quot;--- Round &#123;t[&#x27;round&#x27;]&#125; (messages: &#123;t[&#x27;messages_count&#x27;]&#125;, &quot; f&quot;~&#123;t[&#x27;estimated_tokens&#x27;]&#125; tokens) ---&quot;) if &quot;tool_calls&quot; in t: print(f&quot; Tool Call: &#123;t[&#x27;tool_calls&#x27;][&#x27;name&#x27;]&#125;(&#123;t[&#x27;tool_calls&#x27;][&#x27;args&#x27;]&#125;)&quot;) print(f&quot; Result: &#123;t[&#x27;tool_result&#x27;]&#125;&quot;) else: print(f&quot; Answer: &#123;t[&#x27;final_answer&#x27;][:100]&#125;...&quot;) 九、部署与生产部署架构： 层级 技术选型 关注点 推理层 云端 API (GPT-4o) &#x2F; 本地 GPU (vLLM) 延迟 &lt; 2s, 成本控制 编排层 FastAPI + asyncio 并发处理、超时、熔断 存储层 PostgreSQL + ChromaDB 持久化、检索速度 监控层 OpenTelemetry → Grafana Token 用量、工具调用链、错误率 安全底线： 1234567891011121314151617class SecureAgent(Agent): DANGEROUS_COMMANDS = [&quot;rm -rf&quot;, &quot;sudo&quot;, &quot;chmod 777&quot;, &quot;DROP TABLE&quot;, &quot;format&quot;] def _execute_tool(self, tool_call) -&gt; str: # 安全检查 if tool_call[&quot;name&quot;] == &quot;bash&quot;: cmd = tool_call[&quot;args&quot;].get(&quot;command&quot;, &quot;&quot;) if any(dangerous in cmd for dangerous in self.DANGEROUS_COMMANDS): return json.dumps(&#123;&quot;error&quot;: &quot;危险命令被拦截&quot;, &quot;command&quot;: cmd&#125;) # 需要人工确认 if tool_call[&quot;name&quot;] in [&quot;git_push&quot;, &quot;deploy&quot;, &quot;delete_file&quot;]: confirm = input(f&quot;确认执行 &#123;tool_call[&#x27;name&#x27;]&#125;? (yes/no): &quot;) if confirm.lower() != &quot;yes&quot;: return json.dumps(&#123;&quot;error&quot;: &quot;用户取消操作&quot;&#125;) return super()._execute_tool(tool_call) 成本控制： 123456789101112131415161718class CostTracker: PRICING = &#123; &quot;gpt-4o&quot;: &#123;&quot;input&quot;: 0.0025, &quot;output&quot;: 0.01&#125;, # 每 1K tokens 美元 &quot;claude-3&quot;: &#123;&quot;input&quot;: 0.003, &quot;output&quot;: 0.015&#125;, &#125; def __init__(self, budget: float = 10.0): self.budget = budget self.spent = 0.0 def track(self, model: str, input_tokens: int, output_tokens: int): price = self.PRICING.get(model, &#123;&quot;input&quot;: 0.001, &quot;output&quot;: 0.004&#125;) cost = (input_tokens / 1000) * price[&quot;input&quot;] + (output_tokens / 1000) * price[&quot;output&quot;] self.spent += cost if self.spent &gt; self.budget * 0.8: print(f&quot;⚠️ 预算警告：已使用 &#123;self.spent:.2f&#125;/&#123;self.budget:.2f&#125; 美元&quot;) if self.spent &gt; self.budget: raise RuntimeError(f&quot;预算耗尽：&#123;self.spent:.2f&#125; &gt; &#123;self.budget:.2f&#125;&quot;) 十、入行学习路线 小结：Agent 开发不是调 API 那么简单——从 LLM 封装、工具定义、记忆管理、MCP 集成，到测试、安全、部署，每一个环节都需要工程化的思考。但核心模式是通用的：掌握了这篇文章中的设计模式，你可以在任何框架（或不使用框架）中构建出可靠的 Agent 系统。
